"""
Feast Feature Definitions for Email Intelligence
Defines all 291+ features from email enrichment pipeline

Version: 4.1.0
"""

from datetime import timedelta
from feast import Entity, FeatureView, Field, FileSource
from feast.types import String, Int64, Float64, Bool, UnixTimestamp


# ========== ENTITY DEFINITION ==========

email_entity = Entity(
    name="email",
    description="Email address as primary entity",
    value_type=String
)


# ========== DATA SOURCE ==========

# Parquet files generated by feast_integration.py
email_features_source = FileSource(
    name="email_features_source",
    path="data/email_features.parquet",
    timestamp_field="event_timestamp",
)


# ========== FEATURE VIEW: IDENTITY & VALIDATION ==========

identity_features = FeatureView(
    name="identity_features",
    entities=[email_entity],
    ttl=timedelta(days=90),  # Identity data stable for 90 days
    schema=[
        # Email validation (5)
        Field(name="is_valid_format", dtype=Bool),
        Field(name="is_free_provider", dtype=Bool),
        Field(name="is_disposable", dtype=Bool),
        Field(name="is_corporate", dtype=Bool),
        Field(name="provider_type", dtype=String),

        # Name extraction (8)
        Field(name="has_name_in_email", dtype=Bool),
        Field(name="has_full_name", dtype=Bool),
        Field(name="has_numbers", dtype=Bool),
        Field(name="has_special_chars", dtype=Bool),
        Field(name="name_length", dtype=Int64),
        Field(name="is_professional_format", dtype=Bool),
        Field(name="name_parts_count", dtype=Int64),
        Field(name="username_entropy", dtype=Float64),

        # Domain analysis (12)
        Field(name="domain_length", dtype=Int64),
        Field(name="has_subdomain", dtype=Bool),
        Field(name="tld_type", dtype=String),
        Field(name="is_common_tld", dtype=Bool),
        Field(name="domain_age_days", dtype=Int64),
        Field(name="domain_registered", dtype=Bool),
        Field(name="has_mx_records", dtype=Bool),
        Field(name="mx_count", dtype=Int64),
        Field(name="domain_rank", dtype=Int64),
        Field(name="is_fortune500", dtype=Bool),
        Field(name="is_startup", dtype=Bool),
        Field(name="is_educational", dtype=Bool),
    ],
    source=email_features_source,
    tags={"category": "identity"},
)


