        Field(name="github_account_age_days", dtype=Int64),
        Field(name="github_has_bio", dtype=Bool),
        Field(name="github_has_company", dtype=Bool),
        Field(name="github_has_location", dtype=Bool),
        Field(name="github_has_blog", dtype=Bool),
        Field(name="github_hireable", dtype=Bool),
        Field(name="github_activity_score", dtype=Float64),
        Field(name="github_influence_score", dtype=Float64),
        Field(name="github_primary_language", dtype=String),
        Field(name="github_languages_count", dtype=Int64),
        Field(name="github_verified", dtype=Bool),
        Field(name="github_profile_complete", dtype=Float64),

